import 'package:baseball_detector_flutter/data/result.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/hooks/use_fab_state.dart';

void main() {
  group('useFabState', () {
    const testUserId = 'test-user-id';
    const testTeamId = 'test-team-id';
    final testSession = Session(
      id: 'session-1',
      userId: testUserId,
      teamId: testTeamId,
    );

    final mockProfileStorage = FakeProfileStorage(
      userId: testUserId,
      teamId: testTeamId,
    );

    test('should return available when recording is available', () async {
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'standard',
            maxBalls: 100,
          ),
          currentUsage: 50,
        ),
      );

      final result = buildHook(
        () => useFabState(
          session: testSession,
          teamId: testTeamId,
          canSubscribe: true,
        ),
        wrapper: (child) => ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: child,
        ),
      );

      expect(result.current, FabState.available);
    });

    test('should return needsSubscription when not premium and cannot analyze',
        () {
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'standard',
            maxBalls: 100,
          ),
          currentUsage: 100, // reached limit
        ),
      );

      final result = buildHook(
        () => useFabState(
          session: testSession,
          teamId: testTeamId,
          canSubscribe: true,
        ),
        wrapper: (child) => ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: child,
        ),
      );

      expect(result.current, FabState.needsSubscription);
    });

    test('should return unavailable when premium plan and reached limit',
        () async {
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'premium',
            maxBalls: 1000,
          ),
          currentUsage: 1000, // reached limit
        ),
      );

      final result = await buildHook(
        () => useFabState(
          session: testSession,
          teamId: testTeamId,
          canSubscribe: true,
        ),
        wrapper: (child) => ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: child,
        ),
      );

      expect(result.current, FabState.unavailable);
    });

    test(
        'should return available when premium plan but still has remaining balls',
        () async {
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'premium',
            maxBalls: 1000,
          ),
          currentUsage: 900, // approaching limit but not reached
        ),
      );

      final result = await buildHook(
        () => useFabState(
          session: testSession,
          teamId: testTeamId,
          canSubscribe: true,
        ),
        wrapper: (child) => ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: child,
        ),
      );

      // Premium だがボールが残っている場合は available になるべき
      expect(result.current, FabState.available);
    });

    test('should return unavailable when canSubscribe is false', () async {
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'standard',
            maxBalls: 100,
          ),
          currentUsage: 100, // reached limit
        ),
      );

      final result = await buildHook(
        () => useFabState(
          session: testSession,
          teamId: testTeamId,
          canSubscribe: false, // cannot subscribe
        ),
        wrapper: (child) => ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: child,
        ),
      );

      expect(result.current, FabState.unavailable);
    });

    test('should return unavailable when team not found', () async {
      final result = await buildHook(
        () => useFabState(
          session: testSession,
          teamId: testTeamId,
          canSubscribe: true,
        ),
        wrapper: (child) => ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider
                .overrideWith(() => FakeTeamListController(result: Right([]))),
          ],
          child: child,
        ),
      );

      expect(result.current, FabState.unavailable);
    });
  });
}

