        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'standard',
            maxBalls: 100,
          ),
          currentUsage: 50,
        ),
      );

      final result = await buildHook(
        () => useFabState(
          session: testSession,
          teamId: testTeamId,
          canSubscribe: true,
        ),
        wrapper: (child) => ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
